// Generated by OrchestKit Claude Plugin
// Created: 2026-05-22

/**
 * Session Registrar — SessionStart hook (M168 Phase 2, #1912)
 *
 * Registers this Claude Code session in the shared SQLite session DB
 * (~/.local/state/orchestkit/sessions.db). Runs sweeps on the way in:
 *
 *   1. Mark rows where last_heartbeat < now - 86400 AND status='running'
 *      as status='crashed' (24h liveness window — matches the agent-watchdog
 *      cap from #1882).
 *   2. Delete expired locks (expires_at < now).
 *
 * The INSERT uses OR REPLACE so re-entering an existing sid (e.g. CC resume)
 * just refreshes the row — never blocks the session.
 *
 * Layer 1 of the 4-layer coordination architecture (#1908). Replaces the
 * broken agent-watchdog liveness semantics from #1830.
 *
 * Hook event: SessionStart (async, timeout: 5s).
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { writeWithRetry } from '../lib/session-registry.js';
import { execSync } from 'node:child_process';
import { createHash } from 'node:crypto';
import { readFileSync } from 'node:fs';
import { join } from 'node:path';
import { fileURLToPath } from 'node:url';

const HOOK_NAME = 'lifecycle/session-registrar';
const SECONDS_PER_DAY = 86_400;

/**
 * Resolve the git top-level for the given cwd. Returns cwd itself if not
 * inside a repo. Errors are swallowed — registration never blocks CC.
 */
function getRepoPath(cwd: string): string {
  try {
    const out = execSync('git rev-parse --show-toplevel', {
      cwd,
      stdio: ['ignore', 'pipe', 'ignore'],
      encoding: 'utf8',
      timeout: 1500,
    }).trim();
    return out || cwd;
  } catch {
    return cwd;
  }
}

/** SHA-256 of the repo path — stable identifier across worktrees + reboots. */
function hashRepo(repoPath: string): string {
  return createHash('sha256').update(repoPath).digest('hex').slice(0, 16);
}

/** Resolve the current git branch for cwd. Returns null when not in a repo. */
function getBranch(cwd: string): string | null {
  try {
    const out = execSync('git rev-parse --abbrev-ref HEAD', {
      cwd,
      stdio: ['ignore', 'pipe', 'ignore'],
      encoding: 'utf8',
      timeout: 1500,
    }).trim();
    return out || null;
  } catch {
    return null;
  }
}

/**
 * Resolve the worktree path for the given cwd. Detached worktrees write
 * their .git as a file (gitdir pointer); cwd will be the worktree path
 * unless we are inside a subdir. We resolve via `git rev-parse --git-dir`
 * — for worktrees this points at <main>/.git/worktrees/<name> — and we
 * read the gitdir's `gitdir` file to find the worktree root.
 */
function getWorktreePath(cwd: string, repoPath: string): string | null {
  try {
    const out = execSync('git rev-parse --git-common-dir', {
      cwd,
      stdio: ['ignore', 'pipe', 'ignore'],
      encoding: 'utf8',
      timeout: 1500,
    }).trim();
    // If common-dir == git-dir, we're in the main worktree.
    const gitDir = execSync('git rev-parse --git-dir', {
      cwd,
      stdio: ['ignore', 'pipe', 'ignore'],
      encoding: 'utf8',
      timeout: 1500,
    }).trim();
    if (gitDir === out) return null;
    // For linked worktrees, git rev-parse --show-toplevel returns the worktree path.
    return repoPath;
  } catch {
    return null;
  }
}

/** Best-effort read of the OrchestKit package version. */
function getOrkVersion(): string | null {
  try {
    const __filename = fileURLToPath(import.meta.url);
    // Walk up from src/hooks/dist/lifecycle/... to find the nearest package.json
    // with name "@orchestkit/hooks" or skip if we can't find it.
    const here = __filename;
    // Hooks ship as bundled .mjs — package.json sits next to dist/.
    // Conservative: just return null when not resolvable.
    const pkgPath = join(here, '..', '..', '..', 'package.json');
    const raw = readFileSync(pkgPath, 'utf8');
    const j = JSON.parse(raw) as { version?: string };
    return j.version ?? null;
  } catch {
    return null;
  }
}

/** Best-effort read of the Claude Code version from env. */
function getCcVersion(): string | null {
  return process.env.CLAUDE_CODE_VERSION || process.env.CC_VERSION || null;
}

/**
 * Sweep stale sessions + expired locks. Runs inside the hook's write
 * transaction. Pure SQL — no JS allocation per row.
 */
function sweep(db: import('better-sqlite3').Database, nowSec: number): void {
  const cutoff = nowSec - SECONDS_PER_DAY;
  db.prepare(
    `UPDATE sessions SET status = 'crashed'
     WHERE last_heartbeat < ? AND status = 'running'`,
  ).run(cutoff);
  db.prepare('DELETE FROM locks WHERE expires_at < ?').run(nowSec);
}

/**
 * Insert (or replace) the session row for this Claude Code process.
 * Idempotent on sid: re-running just refreshes started_at + heartbeat.
 */
function register(
  db: import('better-sqlite3').Database,
  row: {
    sid: string;
    pid: number;
    cwd: string;
    repo_hash: string;
    repo_path: string;
    worktree_path: string | null;
    branch: string | null;
    now: number;
    cc_version: string | null;
    ork_version: string | null;
  },
): void {
  db.prepare(
    `INSERT INTO sessions (
       sid, pid, cwd, repo_hash, repo_path, worktree_path, branch,
       status, started_at, last_heartbeat, cc_version, ork_version
     ) VALUES (
       @sid, @pid, @cwd, @repo_hash, @repo_path, @worktree_path, @branch,
       'running', @now, @now, @cc_version, @ork_version
     )
     ON CONFLICT(sid) DO UPDATE SET
       pid            = excluded.pid,
       cwd            = excluded.cwd,
       repo_hash      = excluded.repo_hash,
       repo_path      = excluded.repo_path,
       worktree_path  = excluded.worktree_path,
       branch         = excluded.branch,
       status         = 'running',
       last_heartbeat = excluded.last_heartbeat,
       cc_version     = excluded.cc_version,
       ork_version    = excluded.ork_version`,
  ).run(row);
}

export function sessionRegistrar(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const sid = input.session_id;
  if (!sid) return outputSilentSuccess();

  const cwd = input.project_dir || process.cwd();
  const repoPath = getRepoPath(cwd);
  const repoHash = hashRepo(repoPath);
  const worktreePath = getWorktreePath(cwd, repoPath);
  const branch = getBranch(cwd);
  const nowSec = Math.floor(Date.now() / 1000);
  const ccVersion = getCcVersion();
  const orkVersion = getOrkVersion();

  try {
    writeWithRetry(db => {
      sweep(db, nowSec);
      register(db, {
        sid,
        pid: process.pid,
        cwd,
        repo_hash: repoHash,
        repo_path: repoPath,
        worktree_path: worktreePath,
        branch,
        now: nowSec,
        cc_version: ccVersion,
        ork_version: orkVersion,
      });
    });
  } catch (err) {
    ctx.log(HOOK_NAME, `register failed: ${(err as Error).message}`);
  }

  return outputSilentSuccess();
}

/** Exposed for tests. */
export const __internals = { hashRepo, sweep, register, getRepoPath };
